&lt;p&gt;&lt;strong&gt;&lt;span data-contrast=&quot;none&quot;&gt;Key Responsibilities:&lt;/span&gt;&lt;/strong&gt;&lt;span data-ccp-props=&quot;{}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Plan, design, build, integrate, and&amp;nbsp;operate&amp;nbsp;on propulsion, fluids, and thermal protection system torch test stands with a high degree of safety, autonomy, accountability, and responsibility.&amp;nbsp;&lt;/span&gt;&lt;span data-ccp-props=&quot;{}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Support additional propulsion and energetics test activities including subsystem, component, and integrated hardware testing.&lt;/span&gt;&lt;span data-ccp-props=&quot;{}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Develop and document test instrumentation and measurement, equipment, methods, and processes.&lt;/span&gt;&lt;span data-ccp-props=&quot;{}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Coordinate with design engineers and technicians on test planning, operations, and analysis.&lt;/span&gt;&lt;span data-ccp-props=&quot;{}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Conduct test readiness reviews.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;&lt;span data-contrast=&quot;none&quot;&gt;Required Qualifications:&lt;/span&gt;&lt;/strong&gt;&lt;span data-ccp-props=&quot;{}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
